import { isNull } from 'lodash-es';
import { type PropsWithChildren } from 'react';

import { DynamicTooltip } from './DynamicTooltip.js';
import { LegacyTemplateTooltip } from '../components/LegacyTemplateTooltip.js';
import { DEFAULT_TRUNCATION_MODE } from '../constants.js';
import { ExternalConfigContext } from '../contexts/ExternalConfigContext.js';
import { useDefaultConfig } from '../hooks/useDefaultConfig.js';
import { useSelector, useTooltipSnapshot } from '../selectors.js';
import type { OverlayTooltipProps } from '../types.js';
import { buildContent } from '../utils/build-content.js';
import { isTooltipDataEmpty } from '../utils.js';

export const DynamicTooltipRenderer = (
  props: PropsWithChildren<OverlayTooltipProps>,
) => {
  useSelector(
    ({ absoluteX, absoluteY, inBounds, pinned }) =>
      `${absoluteX}-${absoluteY}-${inBounds}-${pinned}`,
  );
  const { absoluteX, absoluteY, inBounds, pinned, data } = useTooltipSnapshot();
  const defaultConfig = useDefaultConfig();

  if (
    !inBounds ||
    isNull(absoluteX) ||
    isNull(absoluteY) ||
    isTooltipDataEmpty(data)
  ) {
    return;
  }
  const { config, content } = buildContent(props.children, defaultConfig, {
    userSymbolPosition: props.symbolAlignment,
    userTruncationMode: props.truncation ?? DEFAULT_TRUNCATION_MODE,
    customTooltip: !!props.legacyTemplate,
  });

  if (props.legacyTemplate) {
    return (
      <ExternalConfigContext.Provider value={config}>
        <LegacyTemplateTooltip
          pinned={pinned}
          absoluteX={absoluteX}
          absoluteY={absoluteY}
        >
          {props.legacyTemplate}
        </LegacyTemplateTooltip>
      </ExternalConfigContext.Provider>
    );
  }
  return (
    <DynamicTooltip pinned={pinned} absoluteX={absoluteX} absoluteY={absoluteY}>
      <ExternalConfigContext.Provider value={config}>
        {content}
      </ExternalConfigContext.Provider>
    </DynamicTooltip>
  );
};
